1	import { Router, Response, NextFunction } from 'express';
2	import { z } from 'zod';
3	import path from 'path';
4	import fs from 'fs';
5	import { authenticate, authorize } from '../../middleware/auth';
6	import { AuthenticatedRequest, successResponse, errorResponse } from '../../types';
7	import prisma from '../../lib/prisma';
8	import { cache } from '../../lib/cache';
9	import { processScheduledReport } from './reports.processor';
10	
11	const router = Router();
12	
13	const scheduleReportSchema = z.object({
14	  reportType: z.enum(['KPI_SUMMARY', 'REVIEW_EFFICIENCY', 'INVENTORY_SNAPSHOT']),
15	  scheduledFor: z.string().refine((s) => !isNaN(Date.parse(s)), 'Invalid date'),
16	  format: z.enum(['csv', 'excel']).optional().default('csv'),
17	});
18	
19	router.get(
20	  '/kpi/dashboard',
21	  authenticate,
22	  authorize('MANAGER', 'ADMIN'),
23	  async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
24	    try {
25	      const cacheKey = 'kpi:dashboard';
26	      const cached = cache.get<any>(cacheKey);
27	      if (cached) {
28	        res.json(successResponse(cached));
29	        return;
30	      }
31	
32	      const kpis = await prisma.kpiDaily.findMany({
33	        orderBy: { date: 'desc' },
34	        take: 30,
35	      });
36	
37	      cache.set(cacheKey, kpis);
38	      res.json(successResponse(kpis));
39	    } catch (err) {
40	      next(err);
41	    }
42	  }
43	);
44	
45	router.get(
46	  '/review-efficiency',
47	  authenticate,
48	  authorize('MANAGER', 'ADMIN'),
49	  async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
50	    try {
51	      const reports = await prisma.reportReviewEfficiency.findMany({
52	        orderBy: { date: 'desc' },
53	        take: 30,
54	      });
55	      res.json(successResponse(reports));
56	    } catch (err) {
57	      next(err);
58	    }
59	  }
60	);
61	
62	router.get(
63	  '/scheduled',
64	  authenticate,
65	  async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
66	    try {
67	      const reports = await prisma.scheduledReport.findMany({
68	        where: { requestedBy: req.user!.userId },
69	        orderBy: { createdAt: 'desc' },
70	      });
71	      res.json(successResponse(reports));
72	    } catch (err) {
73	      next(err);
74	    }
75	  }
76	);
77	
78	// POST /reports/schedule — create a scheduled report
79	router.post(
80	  '/schedule',
81	  authenticate,
82	  authorize('MANAGER', 'ADMIN'),
83	  async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
84	    try {
85	      const input = scheduleReportSchema.parse(req.body);
86	      const report = await prisma.scheduledReport.create({
87	        data: {
88	          reportType: input.reportType,
89	          format: input.format,
90	          requestedBy: req.user!.userId,
91	          scheduledTime: new Date(input.scheduledFor),
92	          status: 'PENDING',
93	          filePath: null,
94	        },
95	      });
96	      res.status(201).json(successResponse(report));
97	    } catch (err: any) {
98	      if (err.statusCode) {
99	        res.status(err.statusCode).json(errorResponse(err.code, err.message));
100	        return;
101	      }
102	      next(err);
103	    }
104	  }
105	);
106	
107	// POST /reports/scheduled/:id/process — trigger immediate processing (for testing)
108	router.post(
109	  '/scheduled/:id/process',
110	  authenticate,
111	  authorize('MANAGER', 'ADMIN'),
112	  async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
113	    try {
114	      const id = parseInt(req.params.id as string, 10);
115	      const report = await prisma.scheduledReport.findUnique({ where: { id } });
116	      if (!report) {
117	        res.status(404).json(errorResponse('NOT_FOUND', 'Scheduled report not found'));
118	        return;
119	      }
120	      if (report.requestedBy !== req.user!.userId && req.user!.role !== 'ADMIN' && req.user!.role !== 'MANAGER') {
121	        res.status(403).json(errorResponse('FORBIDDEN', 'Not authorized to process this report'));
122	        return;
123	      }
124	      if (report.status !== 'PENDING') {
125	        res.status(422).json(errorResponse('INVALID_STATE', `Report is already ${report.status}`));
126	        return;
127	      }
128	
129	      const updated = await processScheduledReport(report.id);
130	      res.json(successResponse(updated));
131	    } catch (err: any) {
132	      if (err.statusCode) {
133	        res.status(err.statusCode).json(errorResponse(err.code, err.message));
134	        return;
135	      }
136	      next(err);
137	    }
138	  }
139	);
140	
141	// GET /reports/scheduled/:id/download — download a completed report file
142	router.get(
143	  '/scheduled/:id/download',
144	  authenticate,
145	  authorize('MANAGER', 'ADMIN'),
146	  async (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
147	    try {
148	      const id = parseInt(req.params.id as string, 10);
149	      const report = await prisma.scheduledReport.findUnique({ where: { id } });
150	      if (!report) {
151	        res.status(404).json(errorResponse('NOT_FOUND', 'Scheduled report not found'));
152	        return;
153	      }
154	      if (report.requestedBy !== req.user!.userId && req.user!.role !== 'ADMIN' && req.user!.role !== 'MANAGER') {
155	        res.status(403).json(errorResponse('FORBIDDEN', 'Not authorized to access this report'));
156	        return;
157	      }
158	      if (report.status !== 'READY' || !report.filePath) {
159	        res.status(422).json(errorResponse('NOT_READY', 'Report is not ready for download'));
160	        return;
161	      }
162	
163	      const filePath = report.filePath;
164	      if (!fs.existsSync(filePath)) {
165	        res.status(404).json(errorResponse('FILE_NOT_FOUND', 'Report file not found on disk'));
166	        return;
167	      }
168	
169	      const ext = path.extname(filePath);
170	      const filename = `${report.reportType}_${report.id}${ext}`;
171	      res.download(filePath, filename);
172	    } catch (err) {
173	      next(err);
174	    }
175	  }
176	);
177	
178	export default router;
179	
