246	    if (input.text) {
247	      const { clean, flaggedWords } = await filterContent(input.text);
248	      if (!clean) {
249	        businessError('CONTENT_FILTERED', `Reply contains prohibited words: ${flaggedWords.join(', ')}`, 422);
