1	import prisma from '../../lib/prisma';
2	import { logger } from '../../lib/logger';
3	import { RateTaskInput, AdminAdjustInput } from './trust.schema';
4	
5	function businessError(code: string, message: string, statusCode: number): never {
6	  throw Object.assign(new Error(message), { statusCode, code });
7	}
8	
9	// Credit delta map: rating → credit change
10	const CREDIT_DELTA: Record<number, number> = {
11	  5: 2,
12	  4: 1,
13	  3: 0,
14	  2: -1,
15	  1: -2,
16	};
17	
18	function buildExplanation(rating: number, delta: number, taskId: number): string {
19	  if (delta > 0) return `Received ${rating}★ rating on task #${taskId}: +${delta} trust credit`;
20	  if (delta < 0) return `Received ${rating}★ rating on task #${taskId}: ${delta} trust credit`;
21	  return `Received ${rating}★ rating on task #${taskId}: no trust change`;
22	}
23	
24	export class TrustService {
25	  async getScore(userId: number) {
26	    const score = await prisma.trustScore.findUnique({ where: { userId } });
27	    return score ?? { userId, score: 50 };
28	  }
29	
30	  async getUserHistory(userId: number, page: number, pageSize: number) {
31	    const user = await prisma.user.findUnique({ where: { id: userId } });
32	    if (!user) businessError('NOT_FOUND', 'User not found', 404);
33	    return this.getHistory(userId, page, pageSize);
34	  }
35	
36	  async getHistory(userId: number, page: number, pageSize: number) {
37	    const skip = (page - 1) * pageSize;
38	    const [items, total] = await Promise.all([
39	      prisma.creditHistory.findMany({
40	        where: { userId },
41	        orderBy: { createdAt: 'desc' },
42	        skip,
43	        take: pageSize,
44	      }),
45	      prisma.creditHistory.count({ where: { userId } }),
46	    ]);
47	    return { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
48	  }
49	
50	  async getLeaderboard(limit: number = 10) {
51	    return prisma.trustScore.findMany({
52	      orderBy: { score: 'desc' },
53	      take: limit,
54	      include: { user: { select: { id: true, username: true, displayName: true } } },
55	    });
56	  }
57	
58	  async getAllScores() {
59	    return prisma.trustScore.findMany({
60	      orderBy: { score: 'desc' },
61	      include: { user: { select: { id: true, username: true, displayName: true, role: true } } },
62	    });
63	  }
64	
65	  async rateTask(input: RateTaskInput, raterId: number) {
66	    // Prevent self-rating
67	    if (input.rateeId === raterId) {
68	      businessError('SELF_RATING', 'Cannot rate yourself', 422);
69	    }
70	
71	    // Validate interaction exists
72	    const interaction = await prisma.serviceInteraction.findUnique({
73	      where: { id: input.taskId },
74	    });
75	    if (!interaction) {
76	      businessError('INTERACTION_NOT_FOUND', 'Service interaction not found', 404);
77	    }
78	
79	    // Validate interaction is completed
80	    if (interaction!.status !== 'COMPLETED') {
81	      businessError('INTERACTION_NOT_COMPLETED', 'Can only rate completed interactions', 422);
82	    }
83	
84	    // Validate rater and ratee are both participants
85	    const participantIds = new Set([interaction!.requesterId, interaction!.providerId]);
86	    if (!participantIds.has(raterId) || !participantIds.has(input.rateeId)) {
87	      businessError('NOT_PARTICIPANT', 'Rater and ratee must both be participants of this interaction', 403);
88	    }
89	
90	    // Unique per rater+task
91	    const existing = await prisma.taskRating.findUnique({
92	      where: { raterId_taskId: { raterId, taskId: input.taskId } },
93	    });
94	    if (existing) businessError('DUPLICATE', 'You have already rated this task', 409);
95	
96	    // Verify ratee exists
97	    const ratee = await prisma.user.findUnique({ where: { id: input.rateeId } });
98	    if (!ratee) businessError('NOT_FOUND', 'Ratee user not found', 404);
99	
100	    const delta = CREDIT_DELTA[input.rating] ?? 0;
101	    const explanation = buildExplanation(input.rating, delta, input.taskId);
102	
103	    await prisma.$transaction(async (tx) => {
104	      // Create rating record
105	      await tx.taskRating.create({
106	        data: {
107	          raterId,
108	          rateeId: input.rateeId,
109	          taskId: input.taskId,
110	          rating: input.rating,
111	          comment: input.comment ?? null,
112	        },
113	      });
114	
115	      if (delta !== 0) {
116	        // Upsert trust score, clamp 0-100
117	        const current = await tx.trustScore.findUnique({ where: { userId: input.rateeId } });
118	        const currentScore = Number(current?.score ?? 50);
119	        const newScore = Math.max(0, Math.min(100, currentScore + delta));
120	
121	        await tx.trustScore.upsert({
122	          where: { userId: input.rateeId },
123	          create: { userId: input.rateeId, score: newScore, lastUpdated: new Date() },
124	          update: { score: newScore, lastUpdated: new Date() },
125	        });
126	
127	        // Credit history
128	        await tx.creditHistory.create({
129	          data: {
130	            userId: input.rateeId,
131	            changeAmount: delta,
132	            reason: `Task rating from user #${raterId}`,
133	            sourceType: 'TASK_RATING',
134	            sourceId: input.taskId,
135	            explanation,
136	          },
137	        });
138	      }
139	    });
140	
141	    logger.info({ raterId, rateeId: input.rateeId, taskId: input.taskId, rating: input.rating }, 'Task rated');
142	    return { message: 'Rating submitted', delta, explanation };
143	  }
144	
145	  async adminAdjust(input: AdminAdjustInput, adminId: number) {
146	    const user = await prisma.user.findUnique({ where: { id: input.userId } });
147	    if (!user) businessError('NOT_FOUND', 'User not found', 404);
148	
149	    const current = await prisma.trustScore.findUnique({ where: { userId: input.userId } });
150	    const currentScore = Number(current?.score ?? 50);
151	    const newScore = Math.max(0, Math.min(100, currentScore + input.changeAmount));
152	
153	    await prisma.$transaction(async (tx) => {
154	      await tx.trustScore.upsert({
155	        where: { userId: input.userId },
156	        create: { userId: input.userId, score: newScore, lastUpdated: new Date() },
157	        update: { score: newScore, lastUpdated: new Date() },
158	      });
159	
160	      const direction = input.changeAmount > 0 ? `+${input.changeAmount}` : `${input.changeAmount}`;
161	      await tx.creditHistory.create({
162	        data: {
163	          userId: input.userId,
164	          changeAmount: input.changeAmount,
165	          reason: input.reason,
166	          sourceType: 'ADMIN_ADJUSTMENT',
167	          sourceId: adminId,
168	          explanation: `Admin adjustment by #${adminId}: ${direction} (${input.reason})`,
169	        },
170	      });
171	    });
172	
173	    logger.info({ adminId, targetUserId: input.userId, changeAmount: input.changeAmount }, 'Trust score adjusted by admin');
174	    return { userId: input.userId, previousScore: currentScore, newScore };
175	  }
176	}
177	
178	export const trustService = new TrustService();
