router.post('/adjust', authenticate, authorize('ADMIN'), trustController.adminAdjust);
router.post('/admin-adjust', authenticate, authorize('ADMIN'), trustController.adminAdjust); // alias

const creditRulesSchema = z.record(
  z.string().regex(/^[1-5]$/, 'Keys must be star ratings 1–5'),
  z.number().int().min(-10).max(10)
);

// GET /trust/admin/credit-rules — read current credit delta rules (ADMIN only)
router.get(
  '/admin/credit-rules',
  authenticate,
  authorize('ADMIN'),
  (_req: AuthenticatedRequest, res: Response) => {
    res.json(successResponse(getCreditRules()));
  }
);

// PUT /trust/admin/credit-rules — replace credit delta rules (ADMIN only)
router.put(
  '/admin/credit-rules',
  authenticate,
  authorize('ADMIN'),
  (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    try {
      const parsed = creditRulesSchema.parse(req.body);
      // Convert string keys to numbers
      const numericRules: Record<number, number> = {};
      for (const [k, v] of Object.entries(parsed)) {
        numericRules[Number(k)] = v as number;
      }
      setCreditRules(numericRules);
      res.json(successResponse(getCreditRules()));
    } catch (err) {
      next(err);
    }
  }
);

// DELETE /trust/admin/credit-rules — reset to defaults (ADMIN only)
router.delete(
  '/admin/credit-rules',
  authenticate,
  authorize('ADMIN'),
  (_req: AuthenticatedRequest, res: Response) => {
    resetCreditRules();
    res.json(successResponse(getCreditRules()));
  }
);

export default router;"}

