80	  async rateTask(input: RateTaskInput, raterId: number) {
81	    // Prevent self-rating
82	    if (input.rateeId === raterId) {
83	      businessError('SELF_RATING', 'Cannot rate yourself', 422);
84	    }
85	
86	    // Validate interaction exists
87	    const interaction = await prisma.serviceInteraction.findUnique({
88	      where: { id: input.taskId },
89	    });
90	    if (!interaction) {
91	      businessError('INTERACTION_NOT_FOUND', 'Service interaction not found', 404);
92	    }
93	
94	    // Validate interaction is completed
95	    if (interaction!.status !== 'COMPLETED') {
96	      businessError('INTERACTION_NOT_COMPLETED', 'Can only rate completed interactions', 422);
97	    }
98	
99	    // Validate rater and ratee are both participants
100	    const participantIds = new Set([interaction!.requesterId, interaction!.providerId]);
101	    if (!participantIds.has(raterId) || !participantIds.has(input.rateeId)) {
102	      businessError('NOT_PARTICIPANT', 'Rater and ratee must both be participants of this interaction', 403);
103	    }
104	
105	    // Unique per rater+task
106	    const existing = await prisma.taskRating.findUnique({
107	      where: { raterId_taskId: { raterId, taskId: input.taskId } },
108	    });
109	    if (existing) businessError('DUPLICATE', 'You have already rated this task', 409);
110	
111	    // Verify ratee exists
112	    const ratee = await prisma.user.findUnique({ where: { id: input.rateeId } });
113	    if (!ratee) businessError('NOT_FOUND', 'Ratee user not found', 404);
114	
115	    const delta = getCreditRules()[input.rating] ?? 0;
116	    const explanation = buildExplanation(input.rating, delta, input.taskId);
117	
118	    await prisma.$transaction(async (tx) => {
119	      // Create rating record
120	      await tx.taskRating.create({
121	        data: {
122	          raterId,
123	          rateeId: input.rateeId,
124	          taskId: input.taskId,
125	          rating: input.rating,
126	          comment: input.comment ?? null,
127	        },
128	      });
129	
130	      if (delta !== 0) {
131	        // Upsert trust score, clamp 0-100
132	        const current = await tx.trustScore.findUnique({ where: { userId: input.rateeId } });
133	        const currentScore = Number(current?.score ?? 50);
134	        const newScore = Math.max(0, Math.min(100, currentScore + delta));
135	
136	        await tx.trustScore.upsert({
137	          where: { userId: input.rateeId },
138	          create: { userId: input.rateeId, score: newScore, lastUpdated: new Date() },
139	          update: { score: newScore, lastUpdated: new Date() },
140	        });
141	
142	        // Credit history
143	        await tx.creditHistory.create({
144	          data: {
145	            userId: input.rateeId,
146	            changeAmount: delta,
147	            reason: `Task rating from user #${raterId}`,
148	            sourceType: 'TASK_RATING',
149	            sourceId: input.taskId,
150	            explanation,
151	          },
152	        });
153	      }
154	    });
155	
156	    logger.info({ raterId, rateeId: input.rateeId, taskId: input.taskId, rating: input.rating }, 'Task rated');
157	    return { message: 'Rating submitted', delta, explanation };
158	  }
