163	
164	    const current = await prisma.trustScore.findUnique({ where: { userId: input.userId } });
165	    const currentScore = Number(current?.score ?? 50);
166	    const newScore = Math.max(0, Math.min(100, currentScore + input.changeAmount));
167	
168	    await prisma.$transaction(async (tx) => {
169	      await tx.trustScore.upsert({
