177	        data: {
178	          userId: input.userId,
179	          changeAmount: input.changeAmount,
180	          reason: input.reason,
181	          sourceType: 'ADMIN_ADJUSTMENT',
182	          sourceId: adminId,
183	          explanation: `Admin adjustment by #${adminId}: ${direction} (${input.reason})`,
184	        },
