  const entries = Object.entries(rules).map(([k, v]) => ({
    rating: Number(k),
    delta: Number(v),
  }));
  await prisma.$transaction(async (tx) => {
    for (const { rating, delta } of entries) {
      await tx.creditRule.upsert({
        where: { rating },
        create: { rating, delta },
        update: { delta },
      });
    }
  });
}

