422	  promoForm.discountValue = row.discountValue;
423	  promoForm.effectiveStart = new Date(row.effectiveStart).getTime();
424	  promoForm.effectiveEnd = new Date(row.effectiveEnd).getTime();
425	  promoForm.priority = row.priority;
426	  promoForm.isActive = row.isActive;
427	  promoForm.itemIds = row.items?.map((i) => i.itemId) ?? [];
428	  showDrawer.value = true;
