431	async function savePromotion() {
432	  try {
433	    await promoFormRef.value?.validate();
434	  } catch {
435	    return;
436	  }
437	  saveSubmitting.value = true;
438	  try {
439	    const payload = {
440	      name: promoForm.name,
441	      description: promoForm.description || undefined,
442	      discountType: promoForm.discountType,
443	      discountValue: promoForm.discountValue!,
444	      effectiveStart: new Date(promoForm.effectiveStart!).toISOString(),
445	      effectiveEnd: new Date(promoForm.effectiveEnd!).toISOString(),
446	      priority: promoForm.priority,
447	      isActive: promoForm.isActive,
448	      itemIds: promoForm.itemIds.length > 0 ? promoForm.itemIds : undefined,
449	    };
450	
451	    if (editingId.value) {
452	      await promotionsApi.updatePromotion(editingId.value, payload);
453	      successMsg('Promotion updated');
454	    } else {
455	      await promotionsApi.createPromotion(payload);
456	      successMsg('Promotion created');
