502	function addCheckoutItem() {
503	  if (!checkoutItemId.value || !checkoutQty.value || checkoutQty.value < 1) return;
504	  const existing = checkoutItems.value.find((i) => i.itemId === checkoutItemId.value);
505	  if (existing) {
