        await tx.promotionItem.createMany({
          data: input.itemIds.map((itemId) => ({ promotionId: promotion.id, itemId })),
        });
      }

      if (input.exclusions && input.exclusions.length > 0) {
        await tx.promotionExclusion.createMany({
