1	import prisma from '../../lib/prisma';
2	import { logger } from '../../lib/logger';
3	import {
4	  FileReportInput,
5	  TakeActionInput,
6	  FileAppealInput,
7	  ResolveAppealInput,
8	  AddSensitiveWordInput,
9	} from './moderation.schema';
10	import { cache } from '../../lib/cache';
11	
12	function businessError(code: string, message: string, statusCode: number): never {
13	  throw Object.assign(new Error(message), { statusCode, code });
14	}
15	
16	export class ModerationService {
17	  async fileReport(input: FileReportInput, reporterId: number) {
18	    // Prevent duplicate reports from same user on same content
19	    const existing = await prisma.report.findFirst({
20	      where: {
21	        reporterId,
22	        contentType: input.contentType,
23	        contentId: input.contentId,
24	        status: { in: ['PENDING', 'IN_REVIEW'] },
25	      },
26	    });
27	    if (existing) businessError('DUPLICATE', 'You have already reported this content', 409);
28	
29	    const report = await prisma.report.create({
30	      data: {
31	        reporterId,
32	        contentType: input.contentType,
33	        contentId: input.contentId,
34	        reviewId: input.reviewId ?? null,
35	        reason: input.reason,
36	        status: 'PENDING',
37	      },
38	    });
39	
40	    // If content is a review, flag it
41	    if (input.contentType === 'REVIEW' && input.reviewId) {
42	      await prisma.review.update({
43	        where: { id: input.reviewId },
44	        data: { status: 'FLAGGED' },
45	      });
46	    }
47	
48	    logger.info({ reportId: report.id, reporterId, contentType: input.contentType, contentId: input.contentId }, 'Report filed');
49	    return report;
50	  }
51	
52	  async getQueue(status?: string, page = 1, pageSize = 20) {
53	    const skip = (page - 1) * pageSize;
54	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
55	    const where: any = {};
56	    if (status) {
57	      where.status = status;
58	    } else {
59	      where.status = { in: ['PENDING', 'IN_REVIEW'] };
60	    }
61	
62	    const [items, total] = await Promise.all([
63	      prisma.report.findMany({
64	        where,
65	        skip,
66	        take: pageSize,
67	        include: {
68	          reporter: { select: { id: true, displayName: true } },
69	          review: { select: { id: true, text: true, status: true } },
70	          actions: {
71	            include: { moderator: { select: { id: true, displayName: true } } },
72	            orderBy: { createdAt: 'desc' },
73	          },
74	        },
75	        orderBy: { createdAt: 'asc' },
76	      }),
77	      prisma.report.count({ where }),
78	    ]);
79	
80	    return { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
81	  }
