99	  async takeAction(reportId: number, input: TakeActionInput, moderatorId: number) {
100	    const report = await prisma.report.findUnique({
101	      where: { id: reportId },
102	      include: { review: true },
103	    });
104	    if (!report) businessError('NOT_FOUND', 'Report not found', 404);
105	    if (report!.status === 'RESOLVED' || report!.status === 'DISMISSED') {
106	      businessError('INVALID_STATE', 'Report is already closed', 422);
107	    }
108	
109	    const moderationAction = await prisma.$transaction(async (tx) => {
110	      const action = await tx.moderationAction.create({
111	        data: {
112	          reportId,
113	          moderatorId,
114	          action: input.action,
115	          notes: input.notes ?? null,
116	        },
117	      });
118	
119	      // Side-effect on review status
120	      if (report!.reviewId) {
121	        let reviewStatus: string | null = null;
122	        if (input.action === 'HIDE') reviewStatus = 'HIDDEN';
123	        else if (input.action === 'REMOVE') reviewStatus = 'REMOVED';
124	        else if (input.action === 'RESTORE') reviewStatus = 'ACTIVE';
125	
126	        if (reviewStatus) {
127	          await tx.review.update({
128	            where: { id: report!.reviewId },
129	            data: { status: reviewStatus as any },
130	          });
131	        }
132	      }
133	
134	      // Close the report
135	      await tx.report.update({
136	        where: { id: reportId },
137	        data: { status: 'RESOLVED', resolvedAt: new Date() },
138	      });
139	
140	      return action;
141	    });
142	
143	    logger.info({ reportId, action: input.action, moderatorId }, 'Moderation action taken');
144	    return moderationAction;
