173	    // Object-level authorization: only the affected user can appeal
174	    let affectedUserId: number | null = null;
175	    const report = action!.report;
176	    if (report.contentType === 'REVIEW') {
177	      const reviewId = report.reviewId ?? report.contentId;
178	      const review = await prisma.review.findUnique({ where: { id: reviewId } });
179	      if (review) affectedUserId = review.reviewerId;
180	    } else if (report.contentType === 'USER') {
181	      affectedUserId = report.contentId;
182	    }
183	
184	    if (affectedUserId !== userId) {
185	      businessError('FORBIDDEN', 'You can only appeal moderation actions on your own content', 403);
186	    }
187	
188	    // One appeal per user per moderation action
189	    const existing = await prisma.appeal.findFirst({
190	      where: { userId, moderationActionId: input.moderationActionId },
191	    });
192	    if (existing) businessError('DUPLICATE', 'You have already appealed this action', 409);
193	
194	    const appeal = await prisma.appeal.create({
195	      data: {
196	        userId,
197	        moderationActionId: input.moderationActionId,
198	        userStatement: input.userStatement,
199	        status: 'PENDING',
