210	    const where: any = {};
211	    if (status) where.status = status;
212	
213	    const [items, total] = await Promise.all([
214	      prisma.appeal.findMany({
215	        where,
216	        skip,
217	        take: pageSize,
218	        include: {
219	          user: { select: { id: true, displayName: true } },
220	          moderationAction: {
221	            include: {
222	              moderator: { select: { id: true, displayName: true } },
223	              report: { select: { id: true, contentType: true, contentId: true } },
224	            },
225	          },
