235	  async resolveAppeal(appealId: number, input: ResolveAppealInput) {
236	    const appeal = await prisma.appeal.findUnique({
237	      where: { id: appealId },
238	      include: {
239	        moderationAction: {
240	          include: { report: { include: { review: true } } },
241	        },
242	      },
243	    });
244	    if (!appeal) businessError('NOT_FOUND', 'Appeal not found', 404);
245	
246	    // State machine: PENDING/IN_REVIEW → UPHELD/OVERTURNED/IN_REVIEW
247	    const validTransitions: Record<string, string[]> = {
248	      PENDING: ['IN_REVIEW', 'UPHELD', 'OVERTURNED'],
249	      IN_REVIEW: ['UPHELD', 'OVERTURNED'],
250	    };
251	    const allowed = validTransitions[appeal!.status] ?? [];
252	    if (!allowed.includes(input.status)) {
253	      businessError('INVALID_STATE', `Cannot transition from ${appeal!.status} to ${input.status}`, 422);
254	    }
255	
256	    const updated = await prisma.$transaction(async (tx) => {
257	      const resolvedAt = ['UPHELD', 'OVERTURNED'].includes(input.status) ? new Date() : null;
258	
259	      const result = await tx.appeal.update({
260	        where: { id: appealId },
261	        data: {
262	          status: input.status as any,
263	          arbitrationNotes: input.arbitrationNotes ?? null,
264	          outcome: input.outcome ?? null,
265	          resolvedAt,
266	        },
267	      });
268	
269	      // On OVERTURNED: restore the review if the action was HIDE or REMOVE
270	      if (input.status === 'OVERTURNED') {
271	        const originalAction = appeal!.moderationAction.action;
272	        const reviewId = appeal!.moderationAction.report.reviewId;
273	        if (reviewId && (originalAction === 'HIDE' || originalAction === 'REMOVE')) {
274	          await tx.review.update({
275	            where: { id: reviewId },
276	            data: { status: 'ACTIVE' },
277	          });
278	        }
279	      }
280	
281	      return result;
282	    });
283	
284	    logger.info({ appealId, status: input.status }, 'Appeal resolved');
285	    return updated;
286	  }
