    const [items, total] = await Promise.all([
      prisma.moderationAction.findMany({
        where,
        skip,
        take: pageSize,
        include: {
          report: {
            select: {
              id: true,
              contentType: true,
              contentId: true,
              reviewId: true,
              reason: true,
