    <n-tabs v-model:value="activeTab" type="line" animated>
      <!-- ─── Tab 1: My Filed Appeals ──────────────────────────────────────── -->
      <n-tab-pane name="appeals" tab="My Appeals">
        <n-card class="mb-4">
