              }"
            >
              <n-input
                v-model:value="appealForm.userStatement"
                type="textarea"
                :rows="6"
                placeholder="Explain why you believe this moderation action was incorrect or unfair. Be specific and factual (min 10 characters)."
                :maxlength="5000"
                show-count
              />
            </n-form-item>
          </n-form>
