18	/**
19	 * Read credit rules from DB.
20	 * Falls back to DEFAULT_CREDIT_DELTA when the table has no rows so existing
21	 * deployments continue to behave identically without any manual data seeding.
22	 */
23	export async function getCreditRules(): Promise<Record<number, number>> {
24	  const rows = await prisma.creditRule.findMany();
25	  if (rows.length === 0) {
26	    return { ...DEFAULT_CREDIT_DELTA };
27	  }
28	  const rules: Record<number, number> = {};
29	  for (const row of rows) {
30	    rules[row.rating] = row.delta;
31	  }
32	  return rules;
33	}
