35	/**
36	 * Persist a full or partial set of rating→delta overrides.
37	 * Runs as a single transaction so the table is never left in a partial state.
38	 */
39	export async function setCreditRules(rules: Record<number, number>): Promise<void> {
40	  const entries = Object.entries(rules).map(([k, v]) => ({
41	    rating: Number(k),
42	    delta: Number(v),
43	  }));
44	  await prisma.$transaction(async (tx) => {
45	    for (const { rating, delta } of entries) {
46	      await tx.creditRule.upsert({
47	        where: { rating },
48	        create: { rating, delta },
49	        update: { delta },
50	      });
51	    }
52	  });
53	}
