112	      businessError('SELF_RATING', 'Cannot rate yourself', 422);
113	    }
114	
115	    // Validate interaction exists
116	    const interaction = await prisma.serviceInteraction.findUnique({
117	      where: { id: input.taskId },
118	    });
119	    if (!interaction) {
120	      businessError('INTERACTION_NOT_FOUND', 'Service interaction not found', 404);
121	    }
122	
123	    // Validate interaction is completed
124	    if (interaction!.status !== 'COMPLETED') {
125	      businessError('INTERACTION_NOT_COMPLETED', 'Can only rate completed interactions', 422);
126	    }
127	
128	    // Validate rater and ratee are both participants
129	    const participantIds = new Set([interaction!.requesterId, interaction!.providerId]);
130	    if (!participantIds.has(raterId) || !participantIds.has(input.rateeId)) {
131	      businessError('NOT_PARTICIPANT', 'Rater and ratee must both be participants of this interaction', 403);
132	    }
133	
134	    // Unique per rater+task
135	    const existing = await prisma.taskRating.findUnique({
136	      where: { raterId_taskId: { raterId, taskId: input.taskId } },
137	    });
138	    if (existing) businessError('DUPLICATE', 'You have already rated this task', 409);
139	
140	    // Verify ratee exists
141	    const ratee = await prisma.user.findUnique({ where: { id: input.rateeId } });
142	    if (!ratee) businessError('NOT_FOUND', 'Ratee user not found', 404);
143	
144	    const rules = await getCreditRules();
145	    const delta = rules[input.rating] ?? 0;
146	    const explanation = buildExplanation(input.rating, delta, input.taskId);
147	
148	    await prisma.$transaction(async (tx) => {
149	      // Create rating record
150	      await tx.taskRating.create({
151	        data: {
152	          raterId,
153	          rateeId: input.rateeId,
154	          taskId: input.taskId,
155	          rating: input.rating,
156	          comment: input.comment ?? null,
157	        },
158	      });
159	
160	      if (delta !== 0) {
161	        // Upsert trust score, clamp 0-100
162	        const current = await tx.trustScore.findUnique({ where: { userId: input.rateeId } });
163	        const currentScore = Number(current?.score ?? 50);
164	        const newScore = Math.max(0, Math.min(100, currentScore + delta));
165	
166	        await tx.trustScore.upsert({
167	          where: { userId: input.rateeId },
168	          create: { userId: input.rateeId, score: newScore, lastUpdated: new Date() },
169	          update: { score: newScore, lastUpdated: new Date() },
170	        });
171	
172	        // Credit history
173	        await tx.creditHistory.create({
174	          data: {
175	            userId: input.rateeId,
176	            changeAmount: delta,
177	            reason: `Task rating from user #${raterId}`,
178	            sourceType: 'TASK_RATING',
179	            sourceId: input.taskId,
180	            explanation,
181	          },
182	        });
183	      }
184	    });
185	
186	    logger.info({ raterId, rateeId: input.rateeId, taskId: input.taskId, rating: input.rating }, 'Task rated');
187	    return { message: 'Rating submitted', delta, explanation };
188	  }
