666	  async getLowStock(locationId?: number) {
667	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
668	    const where: any = {};
669	    if (locationId) where.locationId = locationId;
670	
671	    const stockLevels = await prisma.stockLevel.findMany({
672	      where,
673	      include: { item: true, location: true, lot: true },
674	    });
675	
676	    return stockLevels
677	      .map((sl) => {
678	        const threshold = Math.max(sl.safetyThreshold, Number(sl.avgDailyUsage) * 7);
679	        return { ...sl, threshold, isLowStock: sl.onHand < threshold };
680	      })
681	      .filter((sl) => sl.isLowStock);
682	  }
