9	// Hardcoded defaults — used when the credit_rules table is empty.
10	const DEFAULT_CREDIT_DELTA: Record<number, number> = {
11	  5: 2,
12	  4: 1,
13	  3: 0,
14	  2: -1,
15	  1: -2,
16	};
