18	/**
19	 * Read credit rules from DB.
20	 * Falls back to DEFAULT_CREDIT_DELTA when the table has no rows so existing
21	 * deployments continue to behave identically without any manual data seeding.
22	 *
23	 * Fallback policy (empty table):
24	 *   5★ → +2, 4★ → +1, 3★ → 0, 2★ → -1, 1★ → -2
25	 *
26	 * To make the active policy fully explicit and auditable, seed the defaults via
27	 *   PUT /trust/admin/credit-rules  {"1":-2,"2":-1,"3":0,"4":1,"5":2}
28	 * or rely on the prisma seed (which inserts defaults only when the table is empty).
29	 */
30	export async function getCreditRules(): Promise<Record<number, number>> {
31	  const rows = await prisma.creditRule.findMany();
32	  if (rows.length === 0) {
33	    // Observable signal: operators can spot this in logs and decide whether to
34	    // persist explicit rules so future changes are tracked in the audit trail.
35	    logger.warn(
36	      { defaults: DEFAULT_CREDIT_DELTA },
37	      'credit_rules table is empty — using hardcoded fallback defaults. ' +
38	        'Run PUT /trust/admin/credit-rules to persist explicit rules.',
39	    );
40	    return { ...DEFAULT_CREDIT_DELTA };
41	  }
42	  logger.debug({ count: rows.length }, 'Using persisted credit rules from DB');
43	  const rules: Record<number, number> = {};
44	  for (const row of rows) {
45	    rules[row.rating] = row.delta;
46	  }
47	  return rules;
48	}
