50	/**
51	 * Persist a full or partial set of rating→delta overrides.
52	 * Runs as a single transaction so the table is never left in a partial state.
53	 */
54	export async function setCreditRules(rules: Record<number, number>): Promise<void> {
55	  const entries = Object.entries(rules).map(([k, v]) => ({
56	    rating: Number(k),
57	    delta: Number(v),
58	  }));
59	  await prisma.$transaction(async (tx) => {
60	    for (const { rating, delta } of entries) {
61	      await tx.creditRule.upsert({
62	        where: { rating },
63	        create: { rating, delta },
64	        update: { delta },
65	      });
66	    }
67	  });
68	}
