     1	import type { PrismaClient } from '@prisma/client';
     2	import { logger } from '../../lib/logger';
     3	
     4	export interface ResolvedReport {
     5	  createdAt: Date;
     6	  resolvedAt: Date;
     7	}
     8	
     9	export interface EfficiencyMetrics {
    10	  avgModerationTimeHrs: number;
    11	  flaggedCount: number;
    12	  resolvedCount: number;
    13	  /** Percentage 0–100: (appealsCount / resolvedCount) * 100 */
    14	  appealRate: number;
    15	}
    16	
    17	/**
    18	 * Pure function — computes the four review-efficiency metrics from raw counts.
    19	 * No I/O; safe to unit-test without Prisma.
    20	 */
    21	export function computeReviewEfficiencyMetrics(
    22	  flaggedCount: number,
    23	  resolvedReports: ResolvedReport[],
    24	  appealsCount: number,
    25	): EfficiencyMetrics {
    26	  const resolvedCount = resolvedReports.length;
    27	
    28	  let totalHrs = 0;
    29	  for (const r of resolvedReports) {
    30	    const diffMs = r.resolvedAt.getTime() - r.createdAt.getTime();
    31	    totalHrs += diffMs / (1000 * 60 * 60);
    32	  }
    33	  const avgModerationTimeHrs =
    34	    resolvedCount > 0 ? totalHrs / resolvedCount : 0;
    35	
    36	  const appealRate =
    37	    resolvedCount > 0 ? (appealsCount / resolvedCount) * 100 : 0;
    38	
    39	  return {
    40	    avgModerationTimeHrs,
    41	    flaggedCount,
    42	    resolvedCount,
    43	    appealRate,
    44	  };
    45	}
    46	
    47	/**
    48	 * Fetches the raw data for `date`'s day window, computes the four metrics,
    49	 * and idempotently upserts one row into `report_review_efficiency`.
    50	 *
    51	 * Accepts `prisma` as a parameter so callers (and tests) can inject it.
    52	 */
    53	export async function aggregateReviewEfficiency(
    54	  date: Date,
    55	  prisma: PrismaClient,
    56	): Promise<void> {
    57	  const dayStart = new Date(date);
    58	  dayStart.setUTCHours(0, 0, 0, 0);
    59	  const dayEnd = new Date(dayStart);
    60	  dayEnd.setUTCDate(dayEnd.getUTCDate() + 1);
    61	
    62	  const [flaggedCount, resolvedReports, appealsCount] = await Promise.all([
    63	    prisma.report.count({
    64	      where: { createdAt: { gte: dayStart, lt: dayEnd } },
    65	    }),
    66	    prisma.report.findMany({
    67	      where: { resolvedAt: { gte: dayStart, lt: dayEnd } },
    68	      select: { createdAt: true, resolvedAt: true },
    69	    }) as Promise<ResolvedReport[]>,
    70	    prisma.appeal.count({
    71	      where: { createdAt: { gte: dayStart, lt: dayEnd } },
    72	    }),
    73	  ]);
    74	
    75	  const metrics = computeReviewEfficiencyMetrics(
    76	    flaggedCount,
    77	    resolvedReports,
    78	    appealsCount,
    79	  );
    80	
    81	  logger.info(
    82	    {
    83	      date: dayStart.toISOString().slice(0, 10),
    84	      flaggedCount: metrics.flaggedCount,
    85	      resolvedCount: metrics.resolvedCount,
    86	      avgModerationTimeHrs: metrics.avgModerationTimeHrs.toFixed(2),
    87	      appealRate: metrics.appealRate.toFixed(2),
    88	    },
    89	    'review-efficiency aggregation computed',
    90	  );
    91	
    92	  await prisma.reportReviewEfficiency.upsert({
    93	    where: { date: dayStart },
    94	    create: {
    95	      date: dayStart,
    96	      avgModerationTimeHrs: metrics.avgModerationTimeHrs,
    97	      flaggedCount: metrics.flaggedCount,
    98	      resolvedCount: metrics.resolvedCount,
    99	      appealRate: metrics.appealRate,
   100	    },
   101	    update: {
   102	      avgModerationTimeHrs: metrics.avgModerationTimeHrs,
   103	      flaggedCount: metrics.flaggedCount,
   104	      resolvedCount: metrics.resolvedCount,
   105	      appealRate: metrics.appealRate,
   106	    },
   107	  });
   108	}
