1	import prisma from '../../lib/prisma';
2	import { logger } from '../../lib/logger';
3	import { filterContent } from '../../lib/contentFilter';
4	import {
5	  CreateReviewInput,
6	  CreateFollowUpInput,
7	  CreateHostReplyInput,
8	  ReviewsQuery,
9	} from './reviews.schema';
10	
11	function businessError(code: string, message: string, statusCode: number): never {
12	  throw Object.assign(new Error(message), { statusCode, code });
13	}
14	
15	function calcOverall(cleanliness: number, communication: number, accuracy: number): number {
16	  return Math.round(((cleanliness + communication + accuracy) / 3) * 10) / 10;
17	}
18	
19	export class ReviewsService {
20	  async createReview(
21	    input: CreateReviewInput,
22	    reviewerId: number,
23	    files: Express.Multer.File[]
24	  ) {
25	    // Content filter
26	    if (input.text) {
27	      const { clean, flaggedWords } = await filterContent(input.text);
28	      if (!clean) {
29	        businessError('CONTENT_FILTERED', `Review contains prohibited words: ${flaggedWords.join(', ')}`, 422);
30	      }
31	    }
32	
33	    // Rate limit: max 3 reviews per hour
34	    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
35	    const recentCount = await prisma.rateLimitLog.count({
36	      where: { userId: reviewerId, action: 'create_review', createdAt: { gte: oneHourAgo } },
37	    });
38	    if (recentCount >= 3) {
39	      businessError('RATE_LIMITED', 'Maximum 3 reviews per hour', 429);
40	    }
41	
42	    // Cannot review yourself
43	    if (input.revieweeId && input.revieweeId === reviewerId) {
44	      businessError('SELF_REVIEW', 'Cannot review yourself', 422);
45	    }
46	
47	    // Validate tag IDs exist
48	    if (input.tagIds && input.tagIds.length > 0) {
49	      const tags = await prisma.tag.findMany({ where: { id: { in: input.tagIds } } });
50	      if (tags.length !== input.tagIds.length) {
51	        businessError('INVALID_TAGS', 'One or more tag IDs do not exist', 422);
52	      }
53	    }
54	
55	    const overallRating = calcOverall(
56	      input.ratingCleanliness,
57	      input.ratingCommunication,
58	      input.ratingAccuracy
59	    );
60	
61	    const review = await prisma.review.create({
62	      data: {
63	        reviewerId,
64	        revieweeId: input.revieweeId ?? null,
65	        targetType: input.targetType,
66	        targetId: input.targetId,
67	        ratingCleanliness: input.ratingCleanliness,
68	        ratingCommunication: input.ratingCommunication,
69	        ratingAccuracy: input.ratingAccuracy,
70	        overallRating,
71	        text: input.text ?? null,
72	        images: files.length > 0
73	          ? {
74	              create: files.map((f) => ({
75	                filePath: f.filename,
76	                fileSize: f.size,
77	              })),
78	            }
79	          : undefined,
80	        tags: input.tagIds && input.tagIds.length > 0
81	          ? { create: input.tagIds.map((tagId) => ({ tagId })) }
82	          : undefined,
83	      },
84	      include: {
85	        images: true,
86	        tags: { include: { tag: true } },
87	      },
88	    });
89	
90	    // Log for rate limiting
91	    await prisma.rateLimitLog.create({
92	      data: { userId: reviewerId, action: 'create_review' },
93	    });
94	
95	    logger.info({ reviewId: review.id, reviewerId }, 'Review created');
96	    return review;
97	  }
98	
99	  async getReview(id: number) {
100	    const review = await prisma.review.findUnique({
101	      where: { id },
102	      include: {
103	        reviewer: { select: { id: true, displayName: true } },
104	        reviewee: { select: { id: true, displayName: true } },
105	        images: true,
106	        tags: { include: { tag: true } },
107	        hostReply: { include: { host: { select: { id: true, displayName: true } } } },
108	        followUps: {
109	          include: {
110	            images: true,
111	            tags: { include: { tag: true } },
112	          },
113	        },
114	      },
115	    });
116	    if (!review) businessError('NOT_FOUND', 'Review not found', 404);
117	    return review;
118	  }
119	
120	  async listReviews(query: ReviewsQuery) {
121	    const page = Math.max(1, parseInt(query.page ?? '1', 10));
122	    const pageSize = Math.min(100, Math.max(1, parseInt(query.pageSize ?? '20', 10)));
123	    const skip = (page - 1) * pageSize;
124	
125	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
126	    const where: any = {};
127	    if (query.targetType) where.targetType = query.targetType;
128	    if (query.status) where.status = query.status;
129	    if (query.revieweeId) where.revieweeId = parseInt(query.revieweeId, 10);
130	    // Top-level reviews only (no follow-ups in list)
131	    where.isFollowUp = false;
132	
133	    const [items, total] = await Promise.all([
134	      prisma.review.findMany({
135	        where,
136	        skip,
137	        take: pageSize,
138	        include: {
139	          reviewer: { select: { id: true, displayName: true } },
140	          images: true,
141	          tags: { include: { tag: true } },
142	          hostReply: true,
143	        },
144	        orderBy: { createdAt: 'desc' },
145	      }),
146	      prisma.review.count({ where }),
147	    ]);
148	
149	    return { items, total, page, pageSize, totalPages: Math.ceil(total / pageSize) };
150	  }
151	
152	  async createFollowUp(
153	    parentReviewId: number,
154	    input: CreateFollowUpInput,
155	    reviewerId: number,
156	    files: Express.Multer.File[]
157	  ) {
158	    const parent = await prisma.review.findUnique({ where: { id: parentReviewId } });
159	    if (!parent) businessError('NOT_FOUND', 'Parent review not found', 404);
160	
161	    if (parent!.reviewerId !== reviewerId) {
162	      businessError('FORBIDDEN', 'Can only follow up on your own reviews', 403);
163	    }
164	
165	    // 7-day window
166	    const daysSince = (Date.now() - parent!.createdAt.getTime()) / (1000 * 60 * 60 * 24);
167	    if (daysSince > 7) {
168	      businessError('WINDOW_EXPIRED', 'Follow-up window of 7 days has passed', 422);
169	    }
170	
171	    // No existing follow-up
172	    const existing = await prisma.review.findFirst({
173	      where: { parentReviewId, isFollowUp: true },
174	    });
175	    if (existing) businessError('DUPLICATE', 'Follow-up already exists for this review', 409);
176	
177	    if (input.text) {
178	      const { clean, flaggedWords } = await filterContent(input.text);
179	      if (!clean) {
180	        businessError('CONTENT_FILTERED', `Content contains prohibited words: ${flaggedWords.join(', ')}`, 422);
181	      }
182	    }
183	
184	    const overallRating = calcOverall(
185	      input.ratingCleanliness,
186	      input.ratingCommunication,
187	      input.ratingAccuracy
188	    );
189	
190	    const followUp = await prisma.review.create({
191	      data: {
192	        reviewerId,
193	        revieweeId: parent!.revieweeId,
194	        targetType: parent!.targetType,
195	        targetId: parent!.targetId,
196	        ratingCleanliness: input.ratingCleanliness,
197	        ratingCommunication: input.ratingCommunication,
198	        ratingAccuracy: input.ratingAccuracy,
199	        overallRating,
200	        text: input.text ?? null,
201	        isFollowUp: true,
202	        parentReviewId,
203	        images: files.length > 0
204	          ? { create: files.map((f) => ({ filePath: f.filename, fileSize: f.size })) }
205	          : undefined,
206	        tags: input.tagIds && input.tagIds.length > 0
207	          ? { create: input.tagIds.map((tagId) => ({ tagId })) }
208	          : undefined,
209	      },
210	      include: {
211	        images: true,
212	        tags: { include: { tag: true } },
213	      },
214	    });
215	
216	    logger.info({ followUpId: followUp.id, parentReviewId, reviewerId }, 'Follow-up created');
217	    return followUp;
218	  }
219	
220	  async createHostReply(
221	    reviewId: number,
222	    input: CreateHostReplyInput,
223	    hostId: number,
224	    _callerRole: string
225	  ) {
226	    const review = await prisma.review.findUnique({ where: { id: reviewId } });
227	    if (!review) businessError('NOT_FOUND', 'Review not found', 404);
228	
229	    // Object-level authorization: HOST can only reply to reviews about them
230	    if (review!.revieweeId !== hostId) {
231	      businessError('FORBIDDEN', 'You can only reply to reviews about your property', 403);
232	    }
233	
234	    // 14-day window
235	    const daysSince = (Date.now() - review!.createdAt.getTime()) / (1000 * 60 * 60 * 24);
236	    if (daysSince > 14) {
237	      businessError('WINDOW_EXPIRED', 'Host reply window of 14 days has passed', 422);
238	    }
239	
240	    // Already replied
241	    const existingReply = await prisma.hostReply.findUnique({ where: { reviewId } });
242	    if (existingReply) businessError('DUPLICATE', 'Host reply already exists for this review', 409);
243	
244	    if (input.text) {
245	      const { clean, flaggedWords } = await filterContent(input.text);
246	      if (!clean) {
247	        businessError('CONTENT_FILTERED', `Reply contains prohibited words: ${flaggedWords.join(', ')}`, 422);
248	      }
249	    }
250	
251	    const reply = await prisma.hostReply.create({
252	      data: { reviewId, hostId, text: input.text },
253	      include: { host: { select: { id: true, displayName: true } } },
254	    });
255	
256	    logger.info({ replyId: reply.id, reviewId, hostId }, 'Host reply created');
257	    return reply;
258	  }
259	
260	  async listTags() {
261	    return prisma.tag.findMany({ orderBy: { name: 'asc' } });
262	  }
263	}
264	
265	export const reviewsService = new ReviewsService();
