2	import { AuthenticatedRequest, errorResponse } from '../types';
3	import prisma from '../lib/prisma';
4	import { config } from '../config';
5	
6	export function rateLimit(action: string, maxPerHour?: number) {
7	  const limit = maxPerHour ?? config.rateLimit.reviewsPerHour;
8	
9	  return async (req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> => {
10	    if (!req.user) {
11	      res.status(401).json(errorResponse('UNAUTHORIZED', 'Authentication required'));
12	      return;
13	    }
14	
15	    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
16	    const count = await prisma.rateLimitLog.count({
17	      where: {
18	        userId: req.user.userId,
19	        action,
20	        createdAt: { gte: oneHourAgo },
21	      },
22	    });
23	
24	    if (count >= limit) {
25	      res.status(429).json(
26	        errorResponse('RATE_LIMITED', `Rate limit exceeded. Maximum ${limit} ${action} actions per hour.`)
27	      );
28	      return;
29	    }
30	
31	    // Log the action
32	    await prisma.rateLimitLog.create({
33	      data: {
34	        userId: req.user.userId,
35	        action,
36	        createdAt: new Date(),
37	      },
38	    });
39	
40	    next();
41	  };
42	}
