1	import { describe, it, expect } from 'vitest';
2	
3	// ─── Variance calculation (mirrors service.finalizeStockCount logic) ──
4	
5	interface Line {
6	  systemQty: number;
7	  countedQty: number;
8	  unitPrice?: number | null;
9	}
10	
11	interface ProcessedLine {
12	  varianceQty: number;
13	  variancePct: number | null;
14	  varianceUsd: number | null;
15	}
16	
17	interface VarianceResult {
18	  processed: ProcessedLine[];
19	  overallVariancePct: number;
20	  totalVarianceUsd: number;
21	  needsApproval: boolean;
22	}
23	
24	function computeVarianceResult(
25	  lines: Line[],
26	  varianceApprovalPct = 5,
27	  varianceApprovalUsd = 250
28	): VarianceResult {
29	  const processed: ProcessedLine[] = lines.map((l) => {
30	    const varianceQty = l.countedQty - l.systemQty;
31	    const variancePct =
32	      l.systemQty === 0 ? null : (Math.abs(varianceQty) / l.systemQty) * 100;
33	    const varianceUsd =
34	      l.unitPrice != null ? Math.abs(varianceQty) * l.unitPrice : null;
35	    return { varianceQty, variancePct, varianceUsd };
36	  });
37	
38	  const totalSystemQty = lines.reduce((s, l) => s + l.systemQty, 0);
39	  const totalAbsVarianceQty = processed.reduce((s, l) => s + Math.abs(l.varianceQty), 0);
40	  const totalVarianceUsd = processed.reduce((s, l) => s + (l.varianceUsd ?? 0), 0);
41	  const overallVariancePct =
42	    totalSystemQty === 0 ? 0 : (totalAbsVarianceQty / totalSystemQty) * 100;
43	  const needsApproval =
44	    overallVariancePct > varianceApprovalPct || totalVarianceUsd > varianceApprovalUsd;
45	
46	  return { processed, overallVariancePct, totalVarianceUsd, needsApproval };
47	}
48	
49	describe('Inventory - Variance Calculation', () => {
50	  it('zero variance auto-approves', () => {
51	    const result = computeVarianceResult([{ systemQty: 100, countedQty: 100, unitPrice: 10 }]);
52	    expect(result.overallVariancePct).toBe(0);
53	    expect(result.totalVarianceUsd).toBe(0);
54	    expect(result.needsApproval).toBe(false);
55	  });
56	
57	  it('percent > 5% triggers PENDING_APPROVAL', () => {
58	    // 10 out of 100 = 10%
59	    const result = computeVarianceResult([{ systemQty: 100, countedQty: 90, unitPrice: 1 }]);
60	    expect(result.overallVariancePct).toBeCloseTo(10);
61	    expect(result.needsApproval).toBe(true);
62	  });
63	
64	  it('USD > $250 triggers PENDING_APPROVAL even when pct is low', () => {
65	    // 1% variance but expensive item: 10 units * $30 = $300
66	    const result = computeVarianceResult([{ systemQty: 1000, countedQty: 990, unitPrice: 30 }]);
67	    expect(result.overallVariancePct).toBeCloseTo(1);
68	    expect(result.totalVarianceUsd).toBe(300);
