107	// ─── Low-stock threshold formula ─────────────────────────────────
108	
109	function isLowStock(onHand: number, safetyThreshold: number, avgDailyUsage: number): boolean {
110	  const threshold = Math.max(safetyThreshold, avgDailyUsage * 7);
111	  return onHand < threshold;
112	}
113	
114	describe('Inventory - Low Stock Threshold', () => {
115	  it('uses safetyThreshold when it is the higher value', () => {
116	    // safetyThreshold=50, avgDailyUsage=2 → usageThreshold=14 → max=50
117	    expect(isLowStock(30, 50, 2)).toBe(true);
118	    expect(isLowStock(60, 50, 2)).toBe(false);
119	  });
120	
121	  it('uses avgDailyUsage * 7 when it is the higher value', () => {
122	    // safetyThreshold=10, avgDailyUsage=5 → usageThreshold=35 → max=35
123	    expect(isLowStock(20, 10, 5)).toBe(true);
124	    expect(isLowStock(40, 10, 5)).toBe(false);
125	  });
126	
127	  it('returns false when onHand equals threshold exactly', () => {
128	    // max(10, 5*7=35) = 35; onHand=35 → NOT low stock
129	    expect(isLowStock(35, 10, 5)).toBe(false);
130	  });
131	
132	  it('falls back to safetyThreshold when avgDailyUsage is zero', () => {
133	    expect(isLowStock(5, 10, 0)).toBe(true);
134	    expect(isLowStock(15, 10, 0)).toBe(false);
135	  });
136	
137	  it('handles fractional avgDailyUsage correctly', () => {
138	    // avgDailyUsage=1.5 → threshold=max(10, 10.5)=10.5; onHand=10 is low
139	    expect(isLowStock(10, 10, 1.5)).toBe(true);
140	    expect(isLowStock(11, 10, 1.5)).toBe(false);
141	  });
142	});
