199	/** Mirrors the guard logic in inventory.service.ts receive() */
200	function validateReceive(item: ItemFlags, input: ReceiveValidationInput): ReceiveValidationError {
201	  if (item.isLotControlled && !input.lotNumber) return 'LOT_REQUIRED';
202	  if (item.requiresExpiration && !input.expirationDate) return 'EXPIRATION_REQUIRED';
203	  return null;
