205	
206	describe('Inventory - Lot-controlled Receiving Validation', () => {
207	  it('rejects lot-controlled item with missing lotNumber', () => {
208	    const err = validateReceive(
209	      { isLotControlled: true, requiresExpiration: false },
210	      { lotNumber: undefined }
211	    );
212	    expect(err).toBe('LOT_REQUIRED');
