4	const CACHE_KEY = 'sensitive_words';
5	
6	export async function loadSensitiveWords(): Promise<string[]> {
7	  const cached = cache.get<string[]>(CACHE_KEY);
8	  if (cached) return cached;
9	
10	  const words = await prisma.sensitiveWord.findMany();
11	  const wordList = words.map((w) => w.word.toLowerCase());
12	  cache.set(CACHE_KEY, wordList, 30 * 60 * 1000); // 30 min cache
13	  return wordList;
14	}
