        .post(`/api/reviews/${baseReviewId}/reply`)
        .set('Authorization', `Bearer ${hostToken}`)
        .send({ text: 'Allowed reply within rate limit.' })
        .expect(201);

      expect(res.body.success).toBe(true);
    });
